func TestScreenshotsFailedFilter(t *testing.T) {
	dbPath := seedNovelStore(t)
	out := runNovelCmd(t, newNovelScreenshotsCmd, "--failed", "--db", dbPath)

	var rows []screenshotRow
	mustUnmarshal(t, out, &rows)

	// acme-sql (failed) and glob-old (failed, archived agents still appear in
	// the bootability audit) — but NOT the two passing agents.
	for _, r := range rows {
		if r.Status == "PASSED" {
			t.Fatalf("--failed must exclude passing agents, got %+v", r)
		}
	}
	if len(rows) == 0 {
		t.Fatal("--failed returned no rows; fixture has failing agents")
	}
}

func TestScreenshotsListsWholeFleet(t *testing.T) {
	dbPath := seedNovelStore(t)
	out := runNovelCmd(t, newNovelScreenshotsCmd, "--db", dbPath)

	var rows []screenshotRow
	mustUnmarshal(t, out, &rows)
	if len(rows) != 4 {
		t.Fatalf("unfiltered audit rows = %d, want all 4 agents", len(rows))
	}
}
